/**
 * Plugin README description validator.
 *
 * Every `packages/eslint-plugin-{slug}/README.md` is generated by
 * `tools/scripts/fix-readmes.ts`, which uses a hardcoded `DESCRIPTIONS` map
 * to pick the per-plugin tagline + the `## Description` paragraph. The
 * generator previously fell back to "Security-focused ESLint plugin." for
 * any plugin missing from the map — which meant the six quality plugins
 * (reliability, conventions, maintainability, modernization, modularity,
 * operability) shipped READMEs whose Description section was off-topic and
 * inaccurate. The docs site fetches these READMEs live via `<RemoteReadme>`,
 * so the bad copy renders on the public docs.
 *
 * This validator locks the contract:
 *   1. Every registered plugin must have a README.md.
 *   2. Non-security plugins must not contain the literal fallback string
 *      "Security-focused ESLint plugin.".
 *   3. The README's `## Description` paragraph must align with the
 *      DESCRIPTIONS entry for that package in fix-readmes.ts — re-running
 *      the generator must be a no-op on a healthy tree.
 */

import { readFileSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import type { PluginEntry } from './plugin-rule-source-drift';

export type PluginReadmeSurface =
  | 'readme-missing'
  | 'readme-fallback-copy'
  | 'readme-description-section-mismatch'
  | 'descriptions-map-missing-entry';

export interface Finding {
  plugin: string;
  package: string;
  file: string;
  surface: PluginReadmeSurface;
  severity: 'error' | 'warning';
  message: string;
}

export interface PluginReadmeDescriptionOptions {
  monorepoRoot: string;
  plugins: readonly PluginEntry[];
}

const FALLBACK_COPY = 'Security-focused ESLint plugin.';

function loadDescriptionsMap(monorepoRoot: string): Map<string, string> {
  // Parse the DESCRIPTIONS object out of `tools/scripts/fix-readmes.ts`
  // with a simple regex — same shape as `rule-mdx-badge-presence.test.ts`'s
  // PLUGINS regex over `plugins.ts`. The generator is plain CommonJS so a
  // string-based parse beats importing it (and avoids running its side
  // effects).
  const scriptPath = join(monorepoRoot, 'tools', 'scripts', 'fix-readmes.ts');
  const src = readFileSync(scriptPath, 'utf-8');
  // Allow an optional TS type annotation between `DESCRIPTIONS` and `=`
  // (the TypeScript variant declares `const DESCRIPTIONS: Record<string, string> = { ... }`).
  const block = src.match(/const DESCRIPTIONS\s*(?::[^=\n{]+)?\s*=\s*\{([\s\S]*?)\n\};/);
  if (!block) throw new Error('DESCRIPTIONS map not found in fix-readmes.ts');

  const map = new Map<string, string>();
  const entryRegex = /['"]([^'"]+)['"]\s*:\s*['"]([^'"]+)['"]/g;
  for (const m of block[1].matchAll(entryRegex)) {
    map.set(m[1], m[2]);
  }
  return map;
}

function extractDescriptionSection(readme: string): string | null {
  // Pull the first paragraph that follows `## Description`. We don't care
  // about trailing sentences — only the lead.
  const m = readme.match(/^##\s+Description\s*\n+([^\n][^\n]*)/m);
  return m ? m[1].trim() : null;
}

export function validatePluginReadmeDescription(
  opts: PluginReadmeDescriptionOptions,
): Finding[] {
  const findings: Finding[] = [];
  const descriptions = loadDescriptionsMap(opts.monorepoRoot);

  for (const plugin of opts.plugins) {
    const readmePath = join(
      opts.monorepoRoot,
      'packages',
      plugin.package,
      'README.md',
    );
    const rel = `packages/${plugin.package}/README.md`;

    if (!existsSync(readmePath)) {
      findings.push({
        plugin: plugin.slug,
        package: plugin.package,
        file: rel,
        surface: 'readme-missing',
        severity: 'error',
        message: `README.md is missing for ${plugin.package}. Run \`node tools/scripts/fix-readmes.ts\` to generate it.`,
      });
      continue;
    }

    const readme = readFileSync(readmePath, 'utf-8');

    // 1. Fallback string only legitimate inside security-pillar plugins.
    if (plugin.pillar !== 'security' && readme.includes(FALLBACK_COPY)) {
      findings.push({
        plugin: plugin.slug,
        package: plugin.package,
        file: rel,
        surface: 'readme-fallback-copy',
        severity: 'error',
        message: `Non-security plugin README contains the security-focused fallback string ("${FALLBACK_COPY}"). The DESCRIPTIONS map in tools/scripts/fix-readmes.ts is missing or wrong for ${plugin.package}.`,
      });
    }

    // 2. DESCRIPTIONS map must have an entry for this package.
    const canonical = descriptions.get(plugin.package);
    if (!canonical) {
      findings.push({
        plugin: plugin.slug,
        package: plugin.package,
        file: 'tools/scripts/fix-readmes.ts',
        surface: 'descriptions-map-missing-entry',
        severity: 'error',
        message: `tools/scripts/fix-readmes.ts DESCRIPTIONS map has no entry for ${plugin.package}. The generator will hard-fail until one is added.`,
      });
      continue;
    }

    // 3. README's `## Description` paragraph must reflect the canonical
    // entry. The generator emits `This plugin provides <canonical>` — the
    // canonical string must appear inside the description paragraph.
    const section = extractDescriptionSection(readme);
    if (!section) {
      findings.push({
        plugin: plugin.slug,
        package: plugin.package,
        file: rel,
        surface: 'readme-description-section-mismatch',
        severity: 'error',
        message: `README has no \`## Description\` section. Re-run \`node tools/scripts/fix-readmes.ts\`.`,
      });
    } else if (!section.includes(canonical)) {
      findings.push({
        plugin: plugin.slug,
        package: plugin.package,
        file: rel,
        surface: 'readme-description-section-mismatch',
        severity: 'error',
        message: `README \`## Description\` paragraph ("${section.slice(0, 100)}…") does not contain the canonical DESCRIPTIONS entry ("${canonical}"). Re-run \`node tools/scripts/fix-readmes.ts\` or update the map.`,
      });
    }
  }

  return findings;
}
